solution_code:
#include <iostream>

template <int N>
int lowerBound(int x) {
    if (x < N) return N;
    return x;
}

int main() {
    int v;
    std::cin >> v;
    std::cout << lowerBound<5>(v) << '\n';
    return 0;
}
